let raw = $json["text"] || "";

raw = raw.replace(/```json\s*/i, "").replace(/```/g, "").trim();

// Extract only the JSON part
const match = raw.match(/\{[\s\S]*\}/);
if (match) {
  raw = match[0];
}

// parsed
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    title: "",
    category: "",
    summary: raw.slice(0, 100),
    tags: []
  };
}

// Add patterns

if (!parsed.title || typeof parsed.title !== "string") {
  parsed.title = "No title";
}

if (!parsed.category || typeof parsed.category !== "string") {
  parsed.category = "Uncategorized";
}

if (!parsed.summary || typeof parsed.summary !== "string") {
  parsed.summary = "No summary";
}

if (!Array.isArray(parsed.tags)) {
  parsed.tags = [];
}

// Sanitize the contents of the tags as well
parsed.tags = parsed.tags
  .filter(tag => typeof tag === "string")
  .slice(0, 3);

// Original item
const item = $input.first();

// Merge
item.json = {
  ...item.json,
  ...parsed
};

// Preserve binary data
item.binary = $input.first().binary;

return [item];

