// Category obtained via OCR
const category = $('Data_Parse_OCR_JSON').first().json.category;

// List of sheets retrieved via the Sheets API
const sheets = $json.sheets || [];

// Create a list of sheet names
const sheetNames = sheets.map(s => s.properties.title);

// Match check
const exists = sheetNames.includes(category);

return [
  {
    json: {
      category: category,
      sheetExists: exists,
      sheetNames: sheetNames
    }
  }
];

